 24→export function RecipeViewScreen({ id }: { id: RecipeId }): JSX.Element | null {
 25→  const recipe = useRecipeById(id);
 26→  const router = useRouter();
 27→  const { t } = useTranslation();
 28→  const { setDebugData } = useDebugContext();
 29→  const { deleteRecipe } = useRecipes();
 30→
 31→  useEffect(() => {
 32→    return () => {
 33→      setDebugData(null);
 34→    };
 35→  }, [setDebugData]);
 36→
 37→  const handleEdit = useCallback((): void => {
 38→    router.push(`/recipe/${id}/edit`);
 39→  }, [router, id]);
 40→
 41→  const handleBack = useCallback((): void => {
 42→    router.back();
 43→  }, [router]);
 44→
 45→  const handleDelete = useCallback((): void => {
 46→    Alert.alert(t("deleteRecipe.title"), t("deleteRecipe.message"), [
 47→      {
 48→        text: t("deleteRecipe.cancel"),
 49→        style: "cancel",
 50→      },
 51→      {
 52→        text: t("deleteRecipe.confirm"),
 53→        style: "destructive",
 54→        onPress: async () => {
 55→          await deleteRecipe(id);
 56→          router.replace("/");
 57→        },
 58→      },
 59→    ]);
 60→  }, [t, deleteRecipe, id, router]);
 61→
 62→  const [isZoomed, setIsZoomed] = useState(false);
 63→  const { width, height } = useWindowDimensions();
 64→  const { coverSize, onImageLoad } = useImageCoverSize(width, height);
 65→
