 67→    opacity: withTiming(isZoomed ? 0 : 1, { duration: 200 }),
 68→  }));
 69→
 70→  if (!recipe) {
 71→    return null;
 72→  }
 73→
 74→  const isProcessing =
 75→    recipe.status === "pending" || recipe.status === "processing";
 76→  const isReady = recipe.status === "ready";
 77→
 78→  return (
 79→    <View style={styles.container}>
 80→      <ZoomableImage
 81→        style={{ width, height }}
 82→        onZoomChange={setIsZoomed}
 83→      >
 84→        <ProgressiveImage
 85→          uri={recipe.photoUri}
 86→          thumbnailUri={recipe.thumbnailUri}
 87→          style={coverSize ?? { width, height }}
 88→          onLoad={onImageLoad}
 89→        />
 90→      </ZoomableImage>
 91→      <Animated.View
 92→        style={[styles.overlay, overlayStyle]}
 93→        pointerEvents={isZoomed ? "none" : "box-none"}
