74→  container: {
75→    overflow: "hidden",
76→  },
77→  image: {
78→    width: "100%",
79→    height: "100%",
80→  },
81→  thumbnailOverlay: {
82→    ...StyleSheet.absoluteFillObject,
83→  },
84→});
