12→export default function AddRecipeScreen(): JSX.Element {
13→  const theme = useTheme();
14→  const { uri } = useLocalSearchParams<{ uri: PhotoUri }>();
15→  const [source, setSource] = useState<SourceId>("");
16→  const { savePending } = useRecipes();
17→  const { touchSource } = useSources();
18→  const { addToQueue } = useBackgroundProcessing();
19→
20→  const handleConfirm = useCallback(
21→    async (sourceOverride?: SourceId) => {
22→      const effectiveSource = sourceOverride ?? source;
23→      if (!uri || !effectiveSource) {
24→        return;
25→      }
26→
27→      const recipe = await savePending(uri, effectiveSource);
28→      await touchSource(effectiveSource);
29→      addToQueue(recipe.id);
30→      router.replace("/");
31→    },
32→    [uri, source, savePending, touchSource, addToQueue]
33→  );
34→
35→  if (!uri) {
36→    return (
37→      <SafeAreaView
38→        edges={["top", "left", "right"]}
39→        style={[styles.container, getThemeColors(theme).container]}
40→      />
41→    );
42→  }
43→
44→  return (
45→    <SafeAreaView
46→      edges={["top", "left", "right"]}
47→      style={[styles.container, getThemeColors(theme).container]}
48→    >
49→      <AddRecipeForm
50→        photoUri={uri}
51→        source={source}
52→        onSourceChange={setSource}
53→        onConfirm={handleConfirm}
54→      />
55→    </SafeAreaView>
56→  );
57→}
58→
59→function getThemeColors(theme: Theme) {
60→  const isDark = theme === "dark";
61→
62→  return {
63→    container: {
64→      backgroundColor: isDark ? "#000000" : "#FFFFFF",
65→    },
66→  };
67→}
68→
69→const styles = StyleSheet.create({
70→  container: {
71→    flex: 1,
72→  },
73→});
