253→      },
254→      childSize: {
255→        width: childSize.width.value,
256→        height: childSize.height.value,
257→      },
258→      maxScale: maxScale.value,
259→      translateX: translate.x.value,
260→      translateY: translate.y.value,
261→      scale: scale.value,
262→    };
263→  };
264→
265→  const setState = (state: CommonTransformState<number>, animate = true) => {
266→    const toScale = clamp(state.scale, minScale, maxScale.value);
267→    const { x: boundX, y: boundY } = boundsFn(toScale);
268→    const toX = clamp(state.translateX, -1 * boundX, boundX);
269→    const toY = clamp(state.translateY, -1 * boundY, boundY);
270→
271→    set(toX, toY, toScale, animate);
272→  };
273→
274→  const getVisibleRect = (): Rect => {
275→    return getRect({
276→      scale: scale.value,
277→      itemSize: {
278→        width: childSize.width.value,
279→        height: childSize.height.value,
280→      },
281→      containerSize: {
282→        width: rootSize.width.value,
283→        height: rootSize.height.value,
284→      },
285→      translation: { x: translate.x.value, y: translate.y.value },
286→    });
287→  };
288→
289→  const zoom = (newScale: number, position?: Vector<number>) => {
290→    const toScale = clamp(newScale, minScale, maxScale.value);
291→
292→    let focal = position;
293→    if (focal !== undefined) {
294→      focal = {
295→        x: clamp(focal.x, 0, childSize.width.value),
296→        y: clamp(focal.y, 0, childSize.height.value),
297→      };
298→    } else {
299→      const frame = getVisibleRect();
300→      focal = {
301→        x: frame.x + frame.width / 2,
302→        y: frame.y + frame.height / 2,
303→      };
304→    }
305→
306→    const centerX = childSize.width.value / 2;
307→    const centerY = childSize.height.value / 2;
308→
309→    const originX = focal.x - centerX;
310→    const originY = focal.y - centerY;
311→    const signedDistanceCenterX = centerX - focal.x;
312→    const signedDistanceCenterY = centerY - focal.y;
313→
314→    const translateX = signedDistanceCenterX + (originX - originX * toScale);
315→    const translateY = signedDistanceCenterY + (originY - originY * toScale);
316→
317→    const { x: boundX, y: boundY } = boundsFn(toScale);
318→    const toX = clamp(translateX, -1 * boundX, boundX);
319→    const toY = clamp(translateY, -1 * boundY, boundY);
320→
321→    set(toX, toY, toScale, true);
322→  };
323→
324→  useImperativeHandle(reference, () => ({
325→    reset: (animate = true) => set(0, 0, minScale, animate),
326→    getState: getState,
327→    setTransformState: setState,
328→    zoom: zoom,
329→    getVisibleRect: getVisibleRect,
330→  }));
331→
332→  const composedTap = Gesture.Exclusive(doubleTap, tap, longPress);
333→  const composedGesture = Gesture.Race(pinch, pan, composedTap);
334→
335→  return (
336→    <View style={[style ?? styles.flex, styles.center]} onLayout={measureRoot}>
337→      <GestureDetector gesture={composedGesture}>
338→        <Animated.View testID={'root'} style={[detectorStyle, styles.center]}>
339→          <Animated.View testID={'child'} onLayout={measureChild}>
340→            {children}
341→          </Animated.View>
342→        </Animated.View>
343→      </GestureDetector>
344→    </View>
345→  );
346→};
