 46→type PanGestureUpdadeEvent = GestureUpdateEvent<
 47→  PanGestureHandlerEventPayload & PanGestureChangeEventPayload
 48→>;
 49→
 50→export const usePanCommons = (options: PanCommmonOptions) => {
 51→  const {
 52→    container,
 53→    translate,
 54→    offset,
 55→    panMode,
 56→    decay,
 57→    boundFn,
 58→    userCallbacks,
 59→  } = options;
 60→
 61→  const { onSwipe, onGestureEnd, onOverPanning } = userCallbacks;
 62→
 63→  const time = useSharedValue<number>(0);
 64→  const position = useVector(0, 0);
 65→  const gestureEnd = useSharedValue<number>(0); // Gimmick value to trigger onGestureEnd callback
 66→  const isWithinBoundX = useSharedValue<boolean>(true);
 67→  const isWithinBoundY = useSharedValue<boolean>(true);
 68→
 69→  const onPanStart = (e: PanGestureEvent) => {
 70→    'worklet';
 71→
 72→    userCallbacks.onPanStart && runOnJS(userCallbacks.onPanStart)(e);
 73→    cancelAnimation(translate.x);
 74→    cancelAnimation(translate.y);
 75→
 76→    offset.x.value = translate.x.value;
 77→    offset.y.value = translate.y.value;
 78→
 79→    time.value = performance.now();
 80→    position.x.value = e.absoluteX;
 81→    position.y.value = e.absoluteY;
 82→  };
 83→
 84→  const onPanChange = (e: PanGestureUpdadeEvent) => {
 85→    'worklet';
 86→
 87→    const toX = e.translationX + offset.x.value;
 88→    const toY = e.translationY + offset.y.value;
 89→
 90→    const { x: boundX, y: boundY } = boundFn();
 91→    const exceedX = Math.max(0, Math.abs(toX) - boundX);
 92→    const exceedY = Math.max(0, Math.abs(toY) - boundY);
 93→    isWithinBoundX.value = exceedX === 0;
 94→    isWithinBoundY.value = exceedY === 0;
 95→
 96→    if ((exceedX > 0 || exceedY > 0) && onOverPanning) {
 97→      const ex = Math.sign(toX) * exceedX;
 98→      const ey = Math.sign(toY) * exceedY;
 99→      onOverPanning(ex, ey);
100→    }
101→
102→    // Simplify both free and clamp pan modes in one condition due to their similarity
103→    if (panMode !== 'friction') {
104→      const isFree = panMode === 'free';
105→      translate.x.value = isFree ? toX : clamp(toX, -1 * boundX, boundX);
106→      translate.y.value = isFree ? toY : clamp(toY, -1 * boundY, boundY);
107→
108→      return;
109→    }
110→
111→    const overScrollFraction =
112→      Math.max(container.width.value, container.height.value) * 1.5;
113→
114→    if (isWithinBoundX.value) {
115→      translate.x.value = toX;
116→    } else {
117→      const fraction = Math.abs(Math.abs(toX) - boundX) / overScrollFraction;
118→      const frictionX = friction(clamp(fraction, 0, 1));
119→      translate.x.value += e.changeX * frictionX;
120→    }
121→
122→    if (isWithinBoundY.value) {
123→      translate.y.value = toY;
124→    } else {
125→      const fraction = Math.abs(Math.abs(toY) - boundY) / overScrollFraction;
126→      const frictionY = friction(clamp(fraction, 0, 1));
127→      translate.y.value += e.changeY * frictionY;
128→    }
129→  };
130→
131→  const onPanEnd = (e: PanGestureEvent) => {
132→    'worklet';
133→
134→    if (panMode === 'clamp' && onSwipe) {
135→      const boundaries = boundFn();
136→      const direction = getSwipeDirection(e, {
137→        boundaries,
138→        time: time.value,
139→        position: { x: position.x.value, y: position.y.value },
140→        translate: { x: translate.x.value, y: translate.y.value },
141→      });
142→
143→      if (direction !== undefined) {
144→        runOnJS(onSwipe)(direction);
145→        return;
146→      }
147→    }
148→
149→    userCallbacks.onPanEnd && runOnJS(userCallbacks.onPanEnd)(e);
150→
151→    const { x: boundX, y: boundY } = boundFn();
152→    const clampX: [number, number] = [-1 * boundX, boundX];
153→    const clampY: [number, number] = [-1 * boundY, boundY];
154→
155→    const toX = clamp(translate.x.value, -1 * boundX, boundX);
156→    const toY = clamp(translate.y.value, -1 * boundY, boundY);
157→
158→    const decayX = decay && isWithinBoundX.value;
159→    const decayY = decay && isWithinBoundY.value;
160→    const decayConfigX = { velocity: e.velocityX, clamp: clampX };
161→    const decayConfigY = { velocity: e.velocityY, clamp: clampY };
162→
163→    translate.x.value = decayX ? withDecay(decayConfigX) : withTiming(toX);
164→    translate.y.value = decayY ? withDecay(decayConfigY) : withTiming(toY);
165→
166→    const restX = Math.abs(Math.abs(translate.x.value) - boundX);
167→    const restY = Math.abs(Math.abs(translate.y.value) - boundY);
168→    gestureEnd.value = restX > restY ? translate.x.value : translate.y.value;
169→
170→    if (decayX || decayY) {
171→      const config = restX > restY ? decayConfigX : decayConfigY;
172→      gestureEnd.value = withDecay(config, (finished) => {
173→        finished && onGestureEnd && runOnJS(onGestureEnd)();
174→      });
175→    } else {
176→      const toValue = restX > restY ? toX : toY;
177→      gestureEnd.value = withTiming(toValue, undefined, (finished) => {
178→        finished && onGestureEnd && runOnJS(onGestureEnd)();
179→      });
180→    }
181→  };
182→
183→  return { onPanStart, onPanChange, onPanEnd };
184→};
